&lt;style&gt;
@keyframes voteBounce {
0% { transform: scale(1); }
50% { transform: scale(1.4); }
100% { transform: scale(1); }
}
.vote-btn.upvoted svg, .vote-btn.downvoted svg {
animation: voteBounce 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}
.reddit-comment { display: flex; gap: 8px; margin-top: 12px; }
.vote-column { display: flex; flex-direction: column; align-items: center; width: 32px; flex-shrink: 0; }
.vote-btn { cursor: pointer; color: #878a8c; background: none; border: none; padding: 2px; }
.vote-btn:hover { color: #ff4500; background: rgba(255, 69, 0, 0.1); border-radius: 4px; }
.vote-score { font-size: 0.8rem; font-weight: 700; margin: 2px 0; color: var(--bs-body-color); }
.vote-btn.upvoted { color: #ff4500; }
.vote-btn.downvoted { color: #7193ff; }
.thread-line-container { width: 100%; display: flex; justify-content: center; flex-grow: 1; cursor: pointer; padding-top: 4px; }
.thread-line { width: 2px; height: 100%; background-color: var(--bs-secondary-bg); transition: background-color 0.2s; }
.thread-line-container:hover .thread-line { background-color: var(--bs-primary); }
.comment-meta { display: flex; align-items: center; gap: 6px; font-size: 0.75rem; margin-bottom: 2px; }
.comment-meta img { width: 24px; height: 24px; border-radius: 50%; object-fit: cover; }
.comment-author { font-weight: 600; color: var(--bs-body-color); }
.comment-time { color: #878a8c; }
.comment-content { font-size: 0.95rem; white-space: pre-wrap; line-height: 1.5; margin-bottom: 4px; word-break: break-word; }
.comment-actions { display: flex; gap: 12px; align-items: center; }
.action-btn { background: none; border: none; color: #878a8c; font-size: 0.75rem; font-weight: 700; display: flex; align-items: center; gap: 4px; padding: 4px 6px; border-radius: 4px; cursor: pointer; }
.action-btn:hover { background-color: var(--bs-secondary-bg); color: var(--bs-body-color); }
.children-container { margin-top: 4px; }
&lt;/style&gt;
&lt;script type=&#34;module&#34;&gt;
import { initializeApp } from &#34;https://www.gstatic.com/firebasejs/10.12.2/firebase-app.js&#34;;
