let articleSlug = window.location.pathname.replace(/\/$/, &#34;&#34;).replace(/^\//, &#34;&#34;);
let allGlobalComments = [];
document.addEventListener(&#34;DOMContentLoaded&#34;, function() {
setTimeout(() =&gt; {
const { auth, googleProvider, githubProvider, signInWithPopup, signOut, onAuthStateChanged } = window.firebaseAuth;
document.getElementById(&#34;google-login-btn&#34;).addEventListener(&#34;click&#34;, () =&gt; signInWithPopup(auth, googleProvider).catch(err =&gt; window.alert(err.message)));
document.getElementById(&#34;github-login-btn&#34;).addEventListener(&#34;click&#34;, () =&gt; signInWithPopup(auth, githubProvider).catch(err =&gt; window.alert(err.message)));
document.getElementById(&#34;logout-btn&#34;).addEventListener(&#34;click&#34;, () =&gt; signOut(auth));
onAuthStateChanged(auth, user =&gt; {
currentUser = user;
if (user) {
const loginModalEl = document.getElementById(&#39;loginModal&#39;);
if (loginModalEl) {
const modalInstance = bootstrap.Modal.getInstance(loginModalEl);
if (modalInstance) modalInstance.hide();
}
document.getElementById(&#34;login-ui&#34;).classList.add(&#34;d-none&#34;);
document.getElementById(&#34;composer-ui&#34;).classList.remove(&#34;d-none&#34;);
document.getElementById(&#34;user-name&#34;).textContent = user.displayName || &#34;Anonymous User&#34;;
document.getElementById(&#34;user-avatar&#34;).src = user.photoURL || &#34;https://ui-avatars.com/api/?name=&#34; + (user.displayName || &#34;A&#34;);
} else {
document.getElementById(&#34;login-ui&#34;).classList.remove(&#34;d-none&#34;);
document.getElementById(&#34;composer-ui&#34;).classList.add(&#34;d-none&#34;);
}
loadComments();
});
}, 500);
