&lt;p&gt;&lt;strong&gt;Source:&lt;/strong&gt;
&lt;a href=&#34;https://www.theverge.com/gadgets/962754/msi-gaming-laptop-ethernet-switch-pc-steam-game-deal-sale&#34;&gt;&lt;em&gt;Original Article&lt;/em&gt;&lt;/a&gt;&lt;/p&gt;
&lt;hr class=&#34;my-5&#34; style=&#34;opacity: 0.15;&#34;&gt;
&lt;div class=&#34;w-100&#34; style=&#34;margin-bottom: 3rem; font-family: -apple-system, BlinkMacSystemFont, &#39;Segoe UI&#39;, Roboto, Helvetica, Arial, sans-serif;&#34;&gt;
&lt;div class=&#34;d-flex justify-content-between align-items-center mb-4&#34;&gt;
&lt;h4 class=&#34;fw-bold mb-0 text-body&#34; id=&#34;discussion-title&#34;&gt;Discussion&lt;/h4&gt;
&lt;select id=&#34;sort-comments&#34; class=&#34;form-select form-select-sm&#34; style=&#34;width: auto; cursor: pointer;&#34;&gt;
&lt;option value=&#34;best&#34;&gt;Best&lt;/option&gt;
&lt;option value=&#34;new&#34;&gt;New&lt;/option&gt;
&lt;option value=&#34;old&#34;&gt;Old&lt;/option&gt;
&lt;/select&gt;
